const crypto = require('crypto');

const input = $input.first().json.body ?? $input.first().json;
const requiredFields = [
  'task_id',
  'session_id',
  'task_type',
  'week_start',
  'week_end',
  'callback_url',
  'wr_attach_url',
];

for (const field of requiredFields) {
  if (!input[field]) {
    throw new Error(`Missing required WR payload field: ${field}`);
  }
}

if (input.task_type !== 'weekly_report.interactive.start') {
  throw new Error(`Unsupported task_type for Qwen dry-run WR workflow: ${input.task_type}`);
}

const expectedCallbackUrl = `/api/internal/ai/tasks/${input.task_id}/result`;
const expectedAttachUrl = `/api/internal/weekly-review/${input.session_id}/attach-ai-result`;
if (input.callback_url !== expectedCallbackUrl) {
  throw new Error(`Unexpected callback_url. Expected ${expectedCallbackUrl}`);
}
if (input.wr_attach_url !== expectedAttachUrl) {
  throw new Error(`Unexpected wr_attach_url. Expected ${expectedAttachUrl}`);
}
if (!$env.IMPERIUM_API_BASE_URL) {
  throw new Error('Missing IMPERIUM_API_BASE_URL environment variable.');
}
if (!$env.INTERNAL_WEBHOOK_SECRET) {
  throw new Error('Missing INTERNAL_WEBHOOK_SECRET environment variable.');
}

const qwenSmokeBody = {
  task_type: 'weekly_report.summary',
  mode: 'weekly_summary',
  input_payload: {
    week_start: input.week_start,
    week_end: input.week_end,
    session_id: input.session_id,
    task_id: input.task_id,
    source: 'n8n_qwen_dry_run_workflow',
  },
};
const qwenSmokeRawBody = JSON.stringify(qwenSmokeBody);
const timestamp = Math.floor(Date.now() / 1000).toString();
const message = `${timestamp}.${qwenSmokeRawBody}`;
const signature = crypto
  .createHmac('sha256', $env.INTERNAL_WEBHOOK_SECRET)
  .update(message)
  .digest('hex');

return [
  {
    json: {
      ...input,
      qwenSmokeRawBody,
      qwenSmokeTimestamp: timestamp,
      qwenSmokeSignature: signature,
      qwenSmokeIdempotencyKey: `wr_qwen_dry_run_smoke_${input.task_id}`,
    },
  },
];

const crypto = require('crypto');

const original = $('Validate Payload and Sign Qwen Smoke').first().json;
const qwen = $('POST Internal Qwen Smoke').first().json;

if (qwen.result_type !== 'weekly_report.summary') {
  throw new Error(`Unexpected Qwen result_type: ${qwen.result_type}`);
}

const aiCallbackBody = {
  result_type: 'weekly_report.summary',
  result_payload: {
    summary: qwen.summary,
    sections: qwen.sections,
    questions: qwen.questions,
    warnings: qwen.warnings,
    source: 'qwen_dry_run',
  },
  model_used: 'qwen2.5:7b-instruct',
  provider: 'qwen-dry-run',
  confidence: qwen.confidence,
  raw_payload: {
    workflow: 'IMPERIUM_WR_INTERACTIVE_START_QWEN_DRY_RUN',
    qwen_response: qwen,
  },
};
const rawBody = JSON.stringify(aiCallbackBody);
const timestamp = Math.floor(Date.now() / 1000).toString();
const message = `${timestamp}.${rawBody}`;
const signature = crypto
  .createHmac('sha256', $env.INTERNAL_WEBHOOK_SECRET)
  .update(message)
  .digest('hex');

return [
  {
    json: {
      ...original,
      aiCallbackRawBody: rawBody,
      aiCallbackTimestamp: timestamp,
      aiCallbackSignature: signature,
      aiCallbackIdempotencyKey: `wr_qwen_dry_run_result_${original.task_id}`,
    },
  },
];

const crypto = require('crypto');

const original = $('Build and Sign AI Result Callback').first().json;
const callbackResponse = $('POST AI Result Callback').first().json;

if (!callbackResponse.result_id) {
  throw new Error('Backend AI result callback did not return result_id.');
}

const attachBody = {
  ai_result_id: callbackResponse.result_id,
};
const rawBody = JSON.stringify(attachBody);
const timestamp = Math.floor(Date.now() / 1000).toString();
const message = `${timestamp}.${rawBody}`;
const signature = crypto
  .createHmac('sha256', $env.INTERNAL_WEBHOOK_SECRET)
  .update(message)
  .digest('hex');

return [
  {
    json: {
      session_id: original.session_id,
      wr_attach_url: original.wr_attach_url,
      result_id: callbackResponse.result_id,
      attachRawBody: rawBody,
      attachTimestamp: timestamp,
      attachSignature: signature,
      attachIdempotencyKey: `wr_qwen_dry_run_attach_${original.session_id}_${callbackResponse.result_id}`,
    },
  },
];
